head.script:
//설명 - 수입일반오더
scwin.memJson = $c.data.getMemInfo();
scwin.lobranCd = scwin.memJson.lobranCd;
scwin.rentcarOfcCd = scwin.memJson.rentcarOfcCd;
scwin.loginId = scwin.memJson.loginId;

scwin.strCurDate = $c.date.getServerDateTime();

scwin.gubun2         = "";
scwin.odrNo          = "";
scwin.type           = "";
scwin.linkPage       = "";
scwin.odrCopy        = "";
scwin.odrKndCd		 = "";	// 오더종류코드
scwin.impExpClsCd	 = "";	// 수출입내수구분코드
scwin.statusFlag	 = "";	// 수정/등록 Flag(C:Regist, U:Update)
scwin.mgntTrgtClntYn = 0; 	// 거래처 관리대상여부
scwin.retrieveYn     = "N";	// 조회여부
scwin.odrCtrlClsCd   = "";  // TS구분 -01적하,02비적하
scwin.excelUploadYn  = 0;	// EXCEL UPLOAD (C3) 여부
scwin.selfClsCd		 = "";	// 자가구분코드 - 자가구분콤보 onSelChange이벤트에서 값 세팅
scwin.assgnWhouseCd	 = "";	// 수입일반인 경우 : bl팝업에서 배정구분코드의 첫째자리가 'B'인 경우, 배정창고코드를 가져온다.
scwin.assgnWhouseNm	 = "";	// 수입일반인 경우 : bl팝업에서 배정구분코드의 첫째자리가 'B'인 경우, 배정창고코드명을 가져온다.

scwin.sellBilgPNoDataCloseTF     = "";  

scwin.reqNo             = ""; // 웹오더요청번호
scwin.web_clntNo        = ""; // 거래처번호
scwin.web_wrkDt         = ""; // 작업일자
scwin.web_wrkHh         = ""; // 작업시간
scwin.web_lineNm        = ""; // LINE명
scwin.web_rltNo         = ""; // 관련번호
scwin.web_vsslNm        = ""; // 선박명
scwin.web_portcnt       = ""; // 항차
scwin.web_closeDt       = ""; // 마감일자
scwin.web_closeHh       = ""; // 마감시간
scwin.web_odrRmk        = ""; // 비고
scwin.web_odrNo         = ""; // 오더번호
scwin.web_onRgnCd       = ""; // 상차지역코드
scwin.web_onRgnNm       = ""; // 상차지역명
scwin.web_onZip         = ""; // 상차지우편번호
scwin.web_onDtl         = ""; // 상차상세
scwin.web_doorRgnCd     = ""; // DOOR지역코드
scwin.web_doorRgnNm     = ""; // DOOR지역명
scwin.web_doorZip       = ""; // DOOR우편번호
scwin.web_doorDtl       = ""; // DOOR상세
scwin.web_doorPicNm     = ""; // DOOR담당자명
scwin.web_doorTelNo     = ""; // DOOR전화번호
scwin.web_offRgnCd      = ""; // 하차지역코드
scwin.web_offRgnNm      = ""; // 하차지역명
scwin.web_offZip        = ""; // 하차지우편번호
scwin.web_offDtl        = ""; // 하차상세

scwin.hid_odrNo          = ""; // 오더번호 odrNo
scwin.hid_odrKndCd       = ""; // 오더종류 odrKndCd
scwin.hid_chkReterieve   = ""; // 조회 여부 확인 type
scwin.hid_linkPage       = ""; // link page 명 linkPage
scwin.hid_odrCopy        = "";
scwin.hid_chkMode        = ""; // 작업 모드
scwin.hid_dptWrkLobranCd = ""; // 작업점소
scwin.hid_adptExchRtDt   = ""; // 적용환율일자
scwin.blInfoYn           = "";

scwin.onpageload = function() {
	scwin.params = $c.data.getParameter();
    scwin.paramTitle = scwin.params["paramTitle"];	
	scwin.indexCtrtNo = scwin.params["indexCtrtNo"];


	// 다른화면에서 넘어오는 경우
    scwin.odrNo		= scwin.params["odrNo"];    // 오더번호
	scwin.odrKndCd 	= scwin.params["odrKndCd"]; // 오더종류
	scwin.type		= scwin.params["type"];     // type
	scwin.linkPage	= scwin.params["linkPage"]; // 링크페이지 종류
	scwin.odrCopy   = scwin.params["odrCopy"];  // 오더복사로 넘길때

    // 웹오더로 넘어오는 값
    scwin.reqNo         = scwin.params["hid_reqNo"];      // 웹오더요청번호
    scwin.web_clntNo    = scwin.params["hid_clntNo"];     // 거래처번호
    scwin.web_wrkDt     = scwin.params["hid_wrkDt"];      // 작업일자
    scwin.web_wrkHh     = scwin.params["hid_wrkHh"];      // 작업시간
    scwin.web_lineNm    = scwin.params["hid_lineNm"];     // LINE명
    scwin.web_rltNo     = scwin.params["hid_rltNo"];      // 관련번호
    scwin.web_vsslNm    = scwin.params["hid_vsslNm"];     // 선박명
    scwin.web_portcnt   = scwin.params["hid_portcnt"];    // 항차
    scwin.web_closeDt   = scwin.params["hid_closeDt"];    // 마감일자
    scwin.web_closeHh   = scwin.params["hid_closeHh"];    // 마감시간
    scwin.web_odrRmk    = scwin.params["hid_odrRmk"];     // 비고
    scwin.web_odrNo     = scwin.params["hid_odrNo"];      // 오더번호
    scwin.web_onRgnCd   = scwin.params["hid_onRgnCd"];    // 상차지역코드
    scwin.web_onRgnNm   = scwin.params["hid_onRgnNm"];    // 상차지역명
    scwin.web_onZip     = scwin.params["hid_onZip"];      // 상차지우편번호
    scwin.web_onDtl     = scwin.params["hid_onDtl"];      // 상차상세
    scwin.web_doorRgnCd = scwin.params["hid_doorRgnCd"];  // DOOR지역코드
    scwin.web_doorRgnNm = scwin.params["hid_doorRgnNm"];  // DOOR지역명
    scwin.web_doorZip   = scwin.params["hid_doorZip"];    // DOOR우편번호
    scwin.web_doorDtl   = scwin.params["hid_doorDtl"];    // DOOR상세
    scwin.web_doorPicNm = scwin.params["hid_doorPicNm"];  // DOOR담당자명
    scwin.web_doorTelNo = scwin.params["hid_doorTelNo"];  // DOOR전화번호
    scwin.web_offRgnCd  = scwin.params["hid_offRgnCd"];   // 하차지역코드
    scwin.web_offRgnNm  = scwin.params["hid_offRgnNm"];   // 하차지역명
    scwin.web_offZip    = scwin.params["hid_offZip"];     // 하차지우편번호
    scwin.web_offDtl    = scwin.params["hid_offDtl"];     // 하차상세

    scwin.hid_odrNo         = scwin.odrNo;
    scwin.hid_odrKndCd      = scwin.odrKndCd;
    scwin.hid_chkReterieve  = scwin.type;
    scwin.hid_linkPage      = scwin.linkPage;
    scwin.hid_odrCopy       = scwin.odrCopy;

	if (scwin.linkPage == "webOdr") {
		grp_header.hide();
		txt_odrNo2.setValue('웹오더생성 [의뢰번호 : '+ scwin.reqNo+ ']');
	} else {
        txt_odrNo2.hide();
	}
};

scwin.ondataload = function() { 
    let dltStr = "dlt_commonCodeSD114"; // "dlt_commonCode" + 그룹코드값으로 데이터리스트 조합
    let dlt = $c.gus.object(dltStr); // 데이터 리스트 객체
    $c.data.dataListFilter(dlt, "fltrCd1 == 'C' || fltrCd1 == 'A'");  //$c.data.dataListFilter 함수를 이용해서 필터

    if ("4AA" != scwin.lobranCd) {
        tbx_onPicNm.setValue("상차담당");
        lc_time.unbindRef();
        lc_time.hide();
    } else {
        tbx_onPicNm.setValue("입고구분");
        ed_onPicNm.unbindRef();
        ed_onPicNm.hide();
    }
};

//-------------------------------------------------------------------------
// UDC 로딩
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
	// 공통코드 설정
    let codeOptions = [ 
        { grpCd : "SD220", compID : "lc_rsnCd" },
        { grpCd : "SD144", compID : "lc_mcomAssgnClsCd" },
        { grpCd : "SD114", compID : "lc_selfClsCd" },
        { grpCd : "SD132", compID : "lc_chClsCd" },
        { grpCd : "SD101", compID : "lc_transCondCd" },
        { grpCd : "SD102", compID : "lc_cntrWtCondCd" },
        { grpCd : "SD125", compID : "lc_odrClsCd", opt : {"range" : "1, 1"} },
        { grpCd : "SD165", compID : "gr_cntrInfo:cntrWrkClsCd"},
    ];

    if("4AA" == scwin.lobranCd) {
        codeOptions.push({ grpCd : "SD401", compID : "lc_time"});
    }

    $c.data.setCommonCode(codeOptions, scwin.loadCommonCodeComplete);
};

scwin.loadCommonCodeComplete = async function() {
	await scwin.f_retrieveCommon();
	await scwin.f_set("INIT", "CREATE");

	if (scwin.linkPage == "odrList") {
		ed_odrNo.setValue(scwin.odrNo.trim());
		await scwin.f_Retrieve();
		if (scwin.odrCopy == "copy") {
			await scwin.set_copy() ;
		}
	}

	// 특이사항저장버튼 숨김
	btn_saveRmk.hide();

	if(scwin.linkPage == "webOdr") {
		ed_ctrtClntNo.setValue(scwin.web_clntNo);
		await scwin.f_openCommonPopUp( 1, 'CTRT', 'T', 'F','F','F' );

		ed_dptWrkPlCd.setValue(scwin.web_onRgnCd);
		ed_dptWrkPlNm.setValue(scwin.web_onRgnNm);
		ed_dptZip.setValue(scwin.web_onZip);
		ed_dptDtl.setValue(scwin.web_onRgnNm);
		ed_arvWrkPlCd.setValue(scwin.web_doorRgnCd);
		ed_arvWrkPlNm.setValue(scwin.web_doorRgnNm);
		ed_arvZip.setValue(scwin.web_doorZip);
		ed_arvDtl.setValue(scwin.web_doorRgnNm);
		ed_offPicNm.setValue(scwin.web_doorPicNm);
		ed_offPicTelNo.setValue(scwin.web_doorTelNo);
		ed_lduldWrkPlCd.setValue(scwin.web_offRgnCd );
		ed_lduldWrkPlNm.setValue(scwin.web_offRgnNm);
		ed_lduldZip.setValue(scwin.web_offZip);
		ed_lduldDtl.setValue(scwin.web_offRgnNm);
		txt_rmk.setValue(scwin.web_odrRmk);
		if(scwin.web_rltNo != "") {
			ed_blNo.setValue(scwin.web_rltNo);
			await scwin.f_openCommonPopUp( 7, '', 'T', 'F','F','F' );
		}
	}

	if (scwin.loginId == "281776" || scwin.loginId == "811160" || scwin.loginId == "290060") {
		btn_temp_save.show();
	}

    // 화면 초기진입시 CH 값초기화
    lc_chClsCd.setSelectedIndex(0);
};

//-------------------------------------------------------------------------
// Event oneditkeyup
//-------------------------------------------------------------------------
// 검색조건 오더번호 Enter 이벤트
scwin.ed_odrNo_oneditkeyup = async function (info, e) {
    $c.gus.cfToUpper(ed_odrNo);

    if (info.keyCode == 13) {
        await scwin.f_Retrieve();
    }
};

//-------------------------------------------------------------------------
// Event onchange
//-------------------------------------------------------------------------
// 계약번호에서 OnSelChange이벤트 발생시
scwin.lc_ctrtNo_onchange = async function (info) {
    if (ds_ctrtNo.getTotalRow() > 0 && scwin.mgntTrgtClntYn != "1") {
		scwin.mgntTrgtClntYn = ds_ctrtNo.getCellData(ds_ctrtNo.getRowPosition(), "mgntTrgtClntYn");

		if (scwin.mgntTrgtClntYn == "1") {
			if (scwin.statusFlag == "C") {
				await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ["본 계약거래처", "관리대상이므로 오더등록"]); // "@은(는) @할 수 없습니다.

				await scwin.f_set("INIT", "INIT"); //초기화
			} else {
				await $c.gus.cfAlertMsg(MSG_SD_WRN_006, ["본 계약거래처", "관리대상"]); // "@은(는) @입니다.
				$c.gus.cfDisableKeyData();
				$c.gus.cfDisableAllBtn();
				$c.gus.cfDisableObjects([btn_confirmOdr, btn_updateCntrInfo]);
				$c.gus.cfEnableBtnOnly([btn_create]);
			}
		} else {
			if (scwin.retrieveYn == "N") {
				await scwin.f_retrieveClntList();
			}
		}
	}

    if (lc_ctrtNo.getValue() != "선택")
		scwin.f_RetrieveCtrtWrkPath(lc_ctrtNo.getValue());

    // 특이사항 숨김여부체크
	if (!$c.gus.cfIsNull(lc_ctrtNo.getValue())) {
		btn_saveRmk.hide();
	} else {
		btn_saveRmk.show();
	}
};

// 오더종류에서 OnSelChange이벤트 발생시
scwin.lc_odrKndCd_onchange = async function (info) {
    if (lc_odrKndCd.getSelectedIndex() != -1) {
        scwin.odrKndCd = ds_odrKndCd.getCellData(lc_odrKndCd.getSelectedIndex(), "cd"); // 오더종류코드
        scwin.impExpClsCd = ds_odrKndCd.getCellData(lc_odrKndCd.getSelectedIndex(), "fltrCd2"); // 수출입구분코드

        if (scwin.impExpClsCd == "null") 
            scwin.impExpClsCd = ""; // TS셔틀컨테이너가 아닌 경우

        await scwin.f_setInterfaceByOdr(scwin.odrKndCd, scwin.impExpClsCd);
    }
};

// 자가구분 Onchange(OnSelChange) 이벤트
scwin.lc_selfClsCd_onchange = function (info) {
	scwin.selfClsCd = ds_odrInfo.getCellData(0, "selfClsCd");
	if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR) {
		if (ds_odrInfo.getCellData(0, "selfClsCd") == DsConstants.SELF_CLS_CD_SELF_SALES) {
            ed_cvsslMgntNo.options.validExp		= "";
            ed_cvsslMgntNo.setMandatory(false); 
            ft_cvsslMgntNo.removeClass("req");

			ed_vsslCd.options.validExp			= "";
            ed_vsslCd.setMandatory(false); 
            ft_vsslCd.removeClass("req");

			ed_portcnt.options.validExp			= "";
            ed_portcnt.setMandatory(false); 
            ft_portcnt.removeClass("req");

			ed_demDt.options.validExp			= "";
            ed_demDt.setMandatory(false); 
            ft_demDt.removeClass("req");
		} else {

            ed_cvsslMgntNo.options.validExp		= "본번:yes";
            ed_cvsslMgntNo.setMandatory(true); 
            ft_cvsslMgntNo.addClass("req");

			ed_vsslCd.options.validExp			= "선박명:yes";
            ed_vsslCd.setMandatory(true); 
            ft_vsslCd.addClass("req");

			ed_portcnt.options.validExp			= "항차:yes";
            ed_portcnt.setMandatory(true); 
            ft_portcnt.addClass("req");

			ed_demDt.options.validExp			= "체선일자:yes";
            ed_demDt.setMandatory(true); 
            ft_demDt.addClass("req");
		}
	}
};

// 요청처명 Onchange(OnSelChange2) 이벤트 발생시
scwin.lc_reqClntNm_onchange = function (info) {
    ed_reqClntNo.setValue(lc_reqClntNm.getValue());
};

// 청구처명 Onchange(OnSelChange2) 이벤트 발생시
scwin.lc_bilgClntNm_onchange = function (info) {
    ed_bilgClntNo.setValue(lc_bilgClntNm.getValue());
};

