// 자가구분 onbeforeselect(OnDropDown) 이벤트
scwin.lc_selfClsCd_onbeforeselect = async function (selectedIndex, index) {
	// 컨테이너를 지정하지 않은 경우 , 자가구분코드를 활성화하므로, 자가구분코드 수정가능하므로 필요한 로직
	var cntrAssgnYn = "N";
	for (var i = 0; i < ds_cntrInfo.getRowCount(); i++) {
		if (ds_cntrInfo.getCellData(i, "cntrNo").trim() != "") {
			cntrAssgnYn = "Y";
			break;
		} 
	}
	if (cntrAssgnYn == "Y") {
		let e = await $c.gus.cfAlertMsg(MSG_CM_ERR_041, ["컨테이너목록에서 컨테이너번호가 지정되어 있으므로, 자가구분코드","변경"]); // @은(는) @할 수 없습니다
        if (e) {
            ds_odrInfo.setCellData(0, "selfClsCd", ds_odrInfo.getOriginalCellData(0, "selfClsCd"));
            return;
        }
	}
};

