													pWtitleSearch,					
													pNoDataCloseTF,					
													null
												);
				} else if(gubun2 == "BILG") {
					pCode = ed_bilgLodeptCd.getValue().trim();
					if (pNoDataCloseTF == "T") {
						ed_bilgLodeptCd.setValue(pCode);
						ed_bilgLodeptNm.setValue("");
						pWhere = "T,J,,,T,,,1";
					} else {
						pWhere = "T,J,,,,,,1";
					}
					pWtitleSearch = "청구부서,부서코드/명";
					scwin.sellBilgPNoDataCloseTF = pNoDataCloseTF;

					udc_bilgLodeptCd.cfCommonPopUpAsync( function(res) { handleCallback(scwin.callBackBilgLodept, res); },
													pCode,						
													pCode,						
													pWinCloseTF,				
													null,						
