// 공통팝업 열기 전에 체크(param설명 : nmLcObj-코드명콤보(LuxCombo), noEdObj-코드(emedit), gubun1, gubun2)
scwin.f_beforeOpenCommonPopUpEdByLc = async function (nmLcObj, noEdObj, gubun1, gubun2, pWinCloseTF, pAllSearchTF) {	
    let noObjVal = noEdObj.getValue().trim();
    if (noObjVal == "") {
        nmLcObj.setSelectedIndex(-1);
    } else {
        nmLcObj.setSelectedIndex(-1);
        await scwin.f_openCommonPopUp(gubun1, gubun2, pWinCloseTF, pAllSearchTF, 'F', 'F');
    }
};

// 컨테이너목록 그리드 실적여부 정보처리
scwin.grdFormatter_wrkRsltsNo = function(wrkRsltsNo) {
    return $c.gus.decode(wrkRsltsNo, "", "미생성", "생성"); 
};

// 새우편번호조회(gubun - 1: 상차지, 2: 작업지, 3:하차지)
scwin.f_openZipPopUpNew = async function(gubun, pClose) {
    var zip, addr;
    if (gubun == 1) {
        zip = ed_dptZip.getValue();
        addr = ed_dptDtl.getValue();
    } else if (gubun == 2) {
        zip = ed_arvZip.getValue();
        addr = ed_arvDtl.getValue();
    } else if (gubun == 3) {
        zip = ed_lduldZip.getValue();
        addr = ed_lduldDtl.getValue();
    }

    var data = {
          zip : zip
        , mchtAddr1 : addr
    };

	let opt = {
        id: "newzipcodePopup",
        popupName: "우편번호 검색",
        modal: true,
        type: "browserPopup",
        width: 500,
        height:550,
        title: "우편번호 검색"
    };    

    var rtnList = await $c.win.openPopup("/ui/cm/zz/newzipcodePopup.xml", opt, data);  
    if (rtnList != null) {
    	if (gubun == 1) {
			ed_dptZip.setValue(rtnList.zip);
            ed_dptDtl.setValue(rtnList.addr1);
		} else if (gubun == 2) {
			ed_arvZip.setValue(rtnList.zip);
            ed_arvDtl.setValue(rtnList.addr1);
		} else if (gubun == 3) {
            ed_lduldZip.setValue(rtnList.zip);
            ed_lduldDtl.setValue(rtnList.addr1);
        }
	} else {
        if (gubun == 1) {
			ed_dptZip.setValue("");
            ed_dptDtl.setValue("");
		} else if (gubun == 2) {
			ed_arvZip.setValue("");
            ed_arvDtl.setValue("");
		} else if (gubun == 3) {
            ed_lduldZip.setValue("");
            ed_lduldDtl.setValue("");
        }
    }
};

// 계약거래처에 해당 되는 컨테이너 계약번호 리스트 조회
scwin.f_retrieveCtrtNo = async function () {
	if (ds_cndCtrtNo.getRowCount() > 0)
        ds_cndCtrtNo.removeAll();

	// 검색조건값 세팅
    var rowIndex = ds_cndCtrtNo.insertRow();
	ds_cndCtrtNo.setCellData(rowIndex, "ctrtClntNo", ed_ctrtClntNo.getValue().trim()); // 계약거래처
	ds_cndCtrtNo.setCellData(rowIndex, "bizDivCntrYn", "1");					       // 사업부문컨테이너여부
	ds_cndCtrtNo.setCellData(rowIndex, "bizDivBulkYn", "");					           // 사업부문벌크여부
	ds_cndCtrtNo.setCellData(rowIndex, "odrKndCd", scwin.odrKndCd);				       // 사업부문벌크여부
	ds_cndCtrtNo.setCellData(rowIndex, "impExpDomesticClsCd", scwin.impExpClsCd);	   // 수출입내수구분코드

