//-------------------------------------------------------------------------
// 화면 onLoad시 초기 데이타 setting
// gubun1 : INIT(초기화), RETRIEVE(조회모드), UPDATE(수정모드), COPY(복사모드)
// gubun2 : INIT(초기화), CREATE(신규모드), ODRKNDCD(오더종류 변경되는 경우)
// 1.초기화,신규모드,오더종류변경되는 경우 : 오더기본정보 세팅(f_setDefaultValue()참조)
//-------------------------------------------------------------------------
scwin.f_set = async function (gubun1, gubun2) {
    scwin.f_getCtrtClntNamDongYn(ed_bilgClntNo.getValue(), "f_set");
    switch (gubun1) {
        case "INIT": // 초기화/신규
        	// 수정사유 TR숨기기 hurrah by 20140219
            tr_editTitle.hide();

            if (gubun2 == "INIT") { 
                // 초기화모드
                scwin.f_clearDataSet();
			  	$c.gus.cfDisableKeyData();
			  	$c.gus.cfDisableAllBtn();
			  	$c.gus.cfEnableBtnOnly([btn_retrieve, btn_create]);
			  	$c.gus.cfEnableObjects([btn_addRow, btn_deleteRow, btn_undoRow]);
			  	$c.gus.cfDisableObjects([btn_confirmOdr, btn_updateCntrInfo, btn_dc, btn_chgWrkPath, btn_repwrk, btn_odrCopy]);
				$c.gus.cfDisableObjects([ed_ctrtClntNm, ed_sellLodeptNm, ed_bilgLodeptNm, ed_dptWrkPlNm,ed_arvWrkPlNm, ed_lineNm, ed_vsslNm, ed_lduldWrkPlNm, ed_railroadDptWrkPlNm, ed_railroadArvWrkPlNm, ed_alloccarPicNm]);

			  	scwin.f_setActiveImgPopUp("D"); //팝업버튼 비활성화
			  	scwin.f_setActiveGrid("D"); //그리드 비활성화

			  	$c.gus.cfInitHidVal([tbl_odrInfoArea]);
				lc_odrKndCd.setSelectedIndex(0);

				rd_wrkPathCopy.setValue("0");

				scwin.statusFlag = "C";   // 수정등록 flag
				scwin.mgntTrgtClntYn = 0; // 계약거래처 관리구분여부 초기화
				scwin.excelUploadYn = 0;  // EXCEL UPLOAD (C3) 여부
            } else if (gubun2 == "CREATE") {
                // 신규모드
	  			scwin.f_clearDataSet();
			  	$c.gus.cfEnableKeyData();
			  	$c.gus.cfDisableKey();
			  	$c.gus.cfEnableAllBtn();
				$c.gus.cfEnableObjects([btn_save, cbx_ctrtComm]);
				$c.gus.cfEnableObjects([btn_addRow, btn_deleteRow, btn_undoRow]);
        		$c.gus.cfDisableObjects([btn_update, btn_delete, btn_confirmOdr, btn_updateCntrInfo, btn_dc, btn_chgWrkPath, btn_repwrk, btn_odrCopy]);
				$c.gus.cfDisableObjects([ed_ctrtClntNm, ed_sellLodeptNm, ed_bilgLodeptNm, ed_dptWrkPlNm,ed_arvWrkPlNm, ed_lineNm, ed_vsslNm, ed_lduldWrkPlNm, ed_railroadDptWrkPlNm, ed_railroadArvWrkPlNm, ed_alloccarPicNm]);

			  	scwin.f_setActiveImgPopUp("E"); //팝업버튼 활성화
			  	scwin.f_setActiveGrid("E"); //그리드활성화
			  	gr_cntrInfo.setReadOnly("column", "dcsnYn", false);

                rd_wrkPathCopy.setValue("0");
			  	$c.gus.cfInitHidVal([tbl_odrInfoArea]);
			  	scwin.mgntTrgtClntYn = 0;	// 계약거래처 관리구분여부 초기화
			  	scwin.excelUploadYn 	= 0;	//EXCEL UPLOAD (C3) 여부

                lc_odrKndCd.setSelectedIndex(0);
                lc_odrKndCd.focus();
                await scwin.lc_odrKndCd_onchange();

				// 작업경로 초기화
				let index = ds_ctrtWrkPath.insertRow();
				ds_ctrtWrkPath.setCellData(index, "ctrtWrkPathSeq", 0);
				ds_ctrtWrkPath.setCellData(index, "rmk", "선택");

				scwin.retrieveYn = "N"; // 조회여부변경
				scwin.statusFlag = "C"; // 수정등록 flag
            } else if (gubun2 == "ODRKNDCD") {
                // 오더종류 변경되는 경우
				if (ds_cndCtrtNo.getRowCount() > 0)
                    ds_cndCtrtNo.removeAll();
				if (ds_ctrtNo.getRowCount() > 0)
					ds_ctrtNo.removeAll();
			 	if (ds_reqClntNo.getRowCount() > 0) 
                    ds_reqClntNo.removeAll();
                if (ds_bilgClntNo.getRowCount() > 0)
                    ds_bilgClntNo.removeAll();
			 	if (ds_cntrInfo.getRowCount() > 0)
                    ds_cntrInfo.removeAll();
				if (ds_blInfo.getRowCount() > 0)
                    ds_blInfo.removeAll();
				if (ds_cndBlNo.getRowCount() > 0)
                    ds_cndBlNo.removeAll();

				// 총건수 세팅
                cntrTotalRows.setValue(ds_cntrInfo.getTotalRow());

				// 초기화
                $c.gus.cfInitObjects(tbl_odrInfoArea, [lc_odrKndCd, scwin.hid_chkReterieve]);
                $c.gus.cfInitObjects(tbl_odrInfoArea2);
			  	scwin.mgntTrgtClntYn = 0; // 계약거래처 관리구분여부 초기화

			  	if (scwin.odrKndCd == DsConstants.ODR_KND_CD_EXAMINE_ODR) {
                    // 검색기
                    lc_mcomAssgnClsCd.setValue("GS");
					$c.gus.cfDisableObjects([ed_railroadDptWrkPlCd, btn_railroadDptWrkPlCd, ed_railroadArvWrkPlCd, btn_railroadArvWrkPlCd, ed_demDt]);
                    ed_demDt.setMandatory(false); 
                    ft_demDt.removeClass("req");
				} else {
					$c.gus.cfEnableObjects([ed_railroadDptWrkPlCd, btn_railroadDptWrkPlCd, ed_railroadArvWrkPlCd, btn_railroadArvWrkPlCd, ed_demDt]);
                    ed_demDt.setMandatory(true);
                    ft_demDt.addClass("req");
				}

				// 매출 청구부서 셋팅
				await scwin.f_setSellAndBilgDept();
		  	}
            scwin.assgnWhouseCd = "";
		  	scwin.assgnWhouseNm = "";
			// 오더별 자가구분코드 LuxeCombo CBData 세팅
            lc_selfClsCd.setValue(DsConstants.SELF_CLS_CD_MCOM_TRANS);
  			scwin.f_setDefaultValue(); // 기본정보세팅
			scwin.hid_chkMode.value = "create";
        break;
        case "RETRIEVE" : // 조회모드
            var odrDcsnYn		= ds_odrInfo.getCellData(0, "odrDcsnYn"); // 확정여부
        	var odrDelYn		= ds_odrInfo.getCellData(1, "odrDelYn");  // 삭제여부

            $c.gus.cfDisableKeyData();
		  	$c.gus.cfDisableAllBtn();

            $c.gus.cfDisableObjects([btn_save, btn_delete, cbx_ctrtComm, btn_addRow, btn_deleteRow, btn_undoRow, btn_saveRmk]);
		  	$c.gus.cfEnableObjects([btn_retrieve, btn_create, btn_update, btn_updateCntrInfo, btn_dc, btn_chgWrkPath, btn_odrCopy]);

		  	// f_setActiveImgPopUp("D"); // 팝업버튼 비활성화
            scwin.f_setActiveImgPopUp("D"); //팝업버튼 비활성화

		  	scwin.f_setActiveGrid("D");     // 그리드 활성화
            gr_cntrInfo.setReadOnly("column", "dcsnYn", true);

			// 수입일반이고, 도착지가 "43D"인 경우, 대표착지 팝업 활성시키기
			scwin.f_enableBtnUpdateRepWrkInfo();

		  	// 확정버튼 control
			if (odrDcsnYn != DsConstants.YN_YES) {
                 // 오더가 확정되지 않은 경우
				$c.gus.cfEnableObjects([btn_confirmOdr]);
				$c.gus.cfEnableBtnOnly([btn_update]);
			} else {
                // 오더가 확정된 경우
				$c.gus.cfDisableObjects([btn_confirmOdr]);
				$c.gus.cfEnableBtnOnly([btn_update]);
			}

			scwin.statusFlag = "R";
			scwin.retrieveYn = "Y";
        break;
        case "UPDATE": // 수정모드
            $c.gus.cfDisableObjects([btn_confirmOdr]);
			scwin.odrKndCd 	= lc_odrKndCd.getValue(); //오더종류
			scwin.impExpClsCd = ds_odrKndCd.getCellData(lc_odrKndCd.getSelectedIndex(), "fltrCd2");

			var cntrInfoRows	= ds_cntrInfo.getRowCount();
        	var odrDcsnYn		= ds_odrInfo.getCellData(0, "odrDcsnYn"); // 확정여부
        	var odrDelYn		= ds_odrInfo.getCellData(0, "odrDelYn");  // 삭제여부

			// 수정사유 TR노출 hurrah by 20140219
        	if (odrDcsnYn == DsConstants.YN_YES) { // 오더가 확정된 경우
			    tr_editTitle.show();
        	}

		  	$c.gus.cfEnableKeyData();
		  	$c.gus.cfDisableKey();
		  	$c.gus.cfEnableAllBtn();
        	$c.gus.cfEnableObjects([btn_delete, btn_save, btn_addRow, btn_deleteRow, btn_undoRow, btn_updateCntrInfo, btn_dc, btn_chgWrkPath, btn_saveRmk, txt_rmk]);
		  	scwin.f_setActiveImgPopUp("E"); //팝업버튼 활성화
			$c.gus.cfDisableObjects([btn_update, ed_lineCd, btn_lineCd, ed_shpCoClntNm, ed_cvsslMgntNo, btn_cvsslMgntNo, ed_blNo, btn_blNo]);
			$c.gus.cfDisableObjects([ed_ctrtClntNm, ed_sellLodeptNm, ed_bilgLodeptNm, ed_dptWrkPlNm,ed_arvWrkPlNm, ed_lineNm, ed_vsslNm, ed_lduldWrkPlNm, ed_railroadDptWrkPlNm, ed_railroadArvWrkPlNm, ed_alloccarPicNm]);

		  	scwin.f_setActiveGrid("E"); // 그리드 비활성화
            gr_cntrInfo.setReadOnly("column", "dcsnYn", true);

			$c.gus.cfEnableObj(lc_odrKndCd, false);	    // 오더종류코드
			$c.gus.cfEnableObj(ed_ctrtClntNo, false);	// 계약거래처코드
			$c.gus.cfEnableObj(ed_ctrtClntNm, false);	// 계약거래처명
			$c.gus.cfEnableObj(lc_ctrtNo, false);		// 계약번호 비활성화
			$c.gus.cfEnableObj(btn_ctrtClntNo, false);	// 계약거래처 PopUp버튼 

			// 오더확정이후 요청처 변경 불가
			if (odrDcsnYn == DsConstants.YN_YES && !$c.gus.cfIsNull(ed_reqClntNo.getValue())) {
                // 오더가 확정된 경우
				$c.gus.cfEnableObj(ed_reqClntNo, false);	//요청처코드
				$c.gus.cfEnableObj(lc_reqClntNm, false);	//요청처명
				$c.gus.cfEnableObj(btn_reqClntNo, false);	//요청처 PopUp버튼
			}

			scwin.statusFlag = "U";
			scwin.f_setInterfaceByOdrOnUpdate();

			// 실적 발생여부를 조회하여 수정항목을 설정
			if (scwin.f_chkResultsConfirmation()) {
				// 수정불가 항목을 Disable 한다.
				// 수정 불가항목 : 오더번호, 오더종류, 계약거래처, 계약번호, 대표거래처
				//			 , 출발작업장, 도착작업장, 작업시작일자, 작업시작시간, 작업종료일자, 작업종료시간
				//			 , 자가구분, 작업유형, 합적여부 (벌크오더 화면에는 해당되지 않는다.
				$c.gus.cfDisableObjects([	ed_dptWrkPlCd,		ed_dptWrkPlNm,		btn_dptWrkPlCd,
									        ed_arvWrkPlCd,		ed_arvWrkPlNm,		btn_arvWrkPlCd,
									        ed_lduldWrkPlCd,	ed_lduldWrkPlNm,	btn_lduldWrkPlCd,
									        ed_wrkStDt,			ed_wrkStHh, 		
									        ed_wrkEndDt,		ed_wrkEndHh,		
									        ed_lduldDt,		    ed_lduldHh,		    
									        ed_railroadDptWrkPlCd, btn_railroadDptWrkPlCd,
									        ed_railroadArvWrkPlCd, btn_railroadArvWrkPlCd,
									        rd_sellYn
                                        ]);
				$c.gus.cfDisableBtnOnly([btn_delete]);
			} else {
				// 컨테이너를 지정하지 않은 경우 , 자가구분코드 활성화
				var cntrAssgnYn = "N";
				for (var i = 0; i < cntrInfoRows; i++) {
					if (ds_cntrInfo.getCellData(i, "cntrNo").trim() != "") {
						cntrAssgnYn = "Y";
						break;
					}
				}
			}

 			scwin.hid_chkMode.value = "";
  			scwin.excelUploadYn 	= 0;	//EXCEL UPLOAD (C3) 여부

	        // 수정사항 체크를 위한 데이터셋 copy hurrah 20140220.
	        ed_rsnTxt.setValue("");
	        ds_odrInfoForCheck.removeAll();
	        $c.gus.cfCopyDataSetHeader(ds_odrInfo, ds_odrInfoForCheck);
	        $c.gus.cf_CopyDataSetValue(ds_odrInfo, ds_odrInfoForCheck);
        break;
        default:
        break;
    }
};

