// 수정모드시, 오더별 세팅
scwin.f_setInterfaceByOdrOnUpdate = function () {		
	scwin.odrKndCd = lc_odrKndCd.getValue(); // 오더종류코드

	if (scwin.odrKndCd == DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR) { // C2
        // 수입일반컨테이너오더
		// 자가영업인경우, 아닌 경우
		if (scwin.selfClsCd == DsConstants.SELF_CLS_CD_SELF_SALES) { // LS
            ed_cvsslMgntNo.options.validExp		= "";
            ed_cvsslMgntNo.setMandatory(false); 
            ft_cvsslMgntNo.removeClass("req");

			ed_vsslCd.options.validExp			= "";
            ed_vsslCd.setMandatory(false); 
            ft_vsslCd.removeClass("req");

			ed_portcnt.options.validExp			= "";
            ed_portcnt.setMandatory(false); 
            ft_portcnt.removeClass("req");

			ed_demDt.options.validExp			= "";
            ed_demDt.setMandatory(false); 
            ft_demDt.removeClass("req");
		} else {
            ed_cvsslMgntNo.options.validExp		= "본번:yes";
            ed_cvsslMgntNo.setMandatory(true); 
            ft_cvsslMgntNo.addClass("req");

			ed_vsslCd.options.validExp			= "선박명:yes";
            ed_vsslCd.setMandatory(true); 
            ft_vsslCd.addClass("req");

			ed_portcnt.options.validExp			= "항차:yes";
            ed_portcnt.setMandatory(true); 
            ft_portcnt.addClass("req");

			ed_demDt.options.validExp			= "체선일자:yes";
            ed_demDt.setMandatory(true); 
            ft_demDt.addClass("req");

		}
	}
};

// 실적 발생여부를 확인
scwin.f_chkResultsConfirmation = function (gubun) {		
	var cntrTotalRows = ds_cntrInfo.getRowCount();

	if (gubun == "CNTR_ROW") {
	  	if (cntrTotalRows > 0) {
	  		if (!$c.gus.cfIsNull(ds_cntrInfo.getCellData(ds_cntrInfo.getRowPosition(), "wrkRsltsNo")))	
                return true; // 실적이 존재하는 경우
	  	}
	} else {
	  	if (cntrTotalRows > 0) {
	  		for (var i = 0; i < cntrTotalRows; i++) {
	  			if (!$c.gus.cfIsNull(ds_cntrInfo.getCellData(i, "wrkRsltsNo")))
                    return true; // 실적이 존재하는 경우
	  		}
	  	}
	}
  	return false;	// 실적이 존재하지 않는 경우
};

