        ds_cntrInfo.setJSON([]); // 오더컨테이너목록

	// 총건수 세팅
    cntrTotalRows.setValue(0);
};

// BlNo와 관련한 DataSet초기화(수입일반인 경우)
scwin.f_clearDataByBlNo = function () {
	$c.gus.cfInitObjects([
                            ed_blNo, 	ed_cvsslMgntNo,		ica_bondTransExpireDt,	ed_vsslCd,		ed_portcnt,
				            ed_vsslNm,	ed_lineCd,			ed_dptWrkPlCd,			ed_dptWrkPlNm,
