				            ed_lineNm,		ed_shpCoClntNm
                        ]);

	scwin.assgnWhouseCd = "";
	scwin.assgnWhouseNm = "";

	lc_mcomAssgnClsCd.setSelectedIndex(0);   // 배정구분코드
