// BL번호에 따른 품명,컨테이너조회(수입일반, CFS셔틀, 세관검사, 검색기인 경우)
scwin.f_retrieveBillOfLadingContainerList = async function() {
	// 라인코드 체크
	if ($c.gus.cfIsNull(ed_lineCd.getValue().trim())) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["라인코드"]); // @을(를) 입력하십시오
		scwin.f_clearDataByBlNo(); // BL번호와 관련한 데이터셋 Clear
		return false;
	}

	// 검색데이터셋 값세팅
	if (ds_cndBlNo.getRowCount() > 0)
        ds_cndBlNo.removeAll();

    var rowIndex = ds_cndBlNo.insertRow();
	ds_cndBlNo.setCellData(rowIndex, "cvsslMgntNo", ed_cvsslMgntNo.getValue().trim());
	ds_cndBlNo.setCellData(rowIndex, "impExpClsCd", "I");
	ds_cndBlNo.setCellData(rowIndex, "mrn", ds_blInfo.getCellData(0, "mrn"));
	ds_cndBlNo.setCellData(rowIndex, "msn", ds_blInfo.getCellData(0, "msn"));
	ds_cndBlNo.setCellData(rowIndex, "hsn", ds_blInfo.getCellData(0, "hsn"));
	ds_cndBlNo.setCellData(rowIndex, "hblNo", ed_blNo.getValue().trim());
	ds_cndBlNo.setCellData(rowIndex, "odrKndCd", scwin.odrKndCd);
	ds_cndBlNo.setCellData(rowIndex, "selfClsCd", lc_selfClsCd.getValue());

    // 조회
	sbm_retrieveBLContainer.userData1 = "noError";
    let e = await $c.sbm.execute(sbm_retrieveBLContainer);
    await scwin.sbm_retrieveBLContainer_submitdone(e);
};

// 수정사유 입력대상여부 체크(오더이력관리용) - 청구거래처를 제외한 모든항목중 변경내용이 있으면 수정사항을 입력해야함.
scwin.f_checkRsn = function() {
	// 매출부서
	if (ds_odrInfoForCheck.getCellData(0, "sellLodeptCd") != ed_sellLodeptCd.getValue()) {
		return true;
	}
	// 청구부서
	if (ds_odrInfoForCheck.getCellData(0, "bilgLodeptCd") != ed_bilgLodeptCd.getValue()) {
		return true;
	}
	// 매출여부
	if (ds_odrInfoForCheck.getCellData(0, "sellYn") != rd_sellYn.getValue()) {
		return true;
	}
	// 선박코드
	if (ds_odrInfoForCheck.getCellData(0, "vsslCd") != ed_vsslCd.getValue()) {
		return true;
	}
	// 항차
	if (ds_odrInfoForCheck.getCellData(0, "portcnt") != ed_portcnt.getValue()) {
		return true;
	}
	// 작업시작일자
	if (ds_odrInfoForCheck.getCellData(0, "wrkStDt") != ed_wrkStDt.getValue()) {
		return true;
	}
	// 작업시작시간
	if (ds_odrInfoForCheck.getCellData(0, "wrkStHh") != ed_wrkStHh.getValue()) {
		return true;
	}
	// 상차지상세
	if (ds_odrInfoForCheck.getCellData(0, "dptDtl") != ed_dptDtl.getValue()) {
		return true;
	}

    if ("4AA" !=scwin.lobranCd) {
	    // 상차담당자명	
        if (ds_odrInfoForCheck.getCellData(0, "onPicNm") != ed_onPicNm.getValue()) {
            return true;
        } else {
            // 상차담당자명	
            if (ds_odrInfoForCheck.getCellData(0, "onPicNm") != lc_time.getValue()) {
                return true;
            }	
        }
    }

	// 상차담당자전화번호
	if (ds_odrInfoForCheck.getCellData(0, "onPicTelNo") != ed_onPicTelNo.getValue()) {
		return true;
	}
	// 작업종료일자
	if (ds_odrInfoForCheck.getCellData(0, "wrkEndDt") != ed_wrkEndDt.getValue()) {
		return true;
	}
	// 작업종료시간
	if (ds_odrInfoForCheck.getCellData(0, "wrkEndHh") != ed_wrkEndHh.getValue()) {
		return true;
	}
	// 작업지상세
	if (ds_odrInfoForCheck.getCellData(0, "arvDtl") != ed_arvDtl.getValue()) {
		return true;
	}
	// 작업지담당자명
	if (ds_odrInfoForCheck.getCellData(0, "offPicNm") != ed_offPicNm.getValue()) {
		return true;
	}
	// 작업지담당자전화번호
	if (ds_odrInfoForCheck.getCellData(0, "offPicTelNo") != ed_offPicTelNo.getValue()) {
		return true;
	}
	// 상하차일자
	if (ds_odrInfoForCheck.getCellData(0, "lduldDt") != ed_lduldDt.getValue()) {
		return true;
	}
	// 상하차시간
	if (ds_odrInfoForCheck.getCellData(0, "lduldHh") != ed_lduldHh.getValue()) {
		return true;
	}
	// 하차지상세
	if (ds_odrInfoForCheck.getCellData(0, "lduldDtl") != ed_lduldDtl.getValue()) {
		return true;
	}
	// 하차지담당자명
	if (ds_odrInfoForCheck.getCellData(0, "lduldPicNm") != ed_lduldPicNm.getValue()) {
		return true;
	}
	// 하차지담당자전화번호
	if (ds_odrInfoForCheck.getCellData(0, "lduldPicTelNo") != ed_lduldPicTelNo.getValue()) {
		return true;
	}
	// 하차지우편번호
	if (ds_odrInfoForCheck.getCellData(0, "lduldZip") != ed_lduldZip.getValue()) {
		return true;
	}
	// 작업지우편번호
	if (ds_odrInfoForCheck.getCellData(0, "arvZip") != ed_arvZip.getValue()) {
		return true;
	}
	// 상차지우편번호
	if (ds_odrInfoForCheck.getCellData(0, "dptZip") != ed_dptZip.getValue()) {
		return true;
	}
	// 보운
	if (ds_odrInfoForCheck.getCellData(0, "bondTransExpireDt") != ica_bondTransExpireDt.getValue()) {
		return true;
	}
	// 배정
	if (ds_odrInfoForCheck.getCellData(0, "mcomAssgnClsCd") != lc_mcomAssgnClsCd.getValue()) {
		return true;
	}
	// 자가
	if (ds_odrInfoForCheck.getCellData(0, "selfClsCd") != lc_selfClsCd.getValue()) {
		return true;
	}
	// ch구분
	if (ds_odrInfoForCheck.getCellData(0, "chClsCd") != ($c.gus.cfIsNull(lc_chClsCd.getValue()) ? 0 : lc_chClsCd.getValue())) {
		return true;
	}
	// 지정
	if (ds_odrInfoForCheck.getCellData(0, "cntrDsgYn") != rd_cntrDsgYn.getValue()) {
		return true;
	}
	// 운송조건
	if (ds_odrInfoForCheck.getCellData(0, "transCondCd") != lc_transCondCd.getValue()) {
		return true;
	}
	// 컨테이너중량조건
	if (ds_odrInfoForCheck.getCellData(0, "cntrWtCondCd") != lc_cntrWtCondCd.getValue()) {
		return true;
	}
	// 채선일자
	if (ds_odrInfoForCheck.getCellData(0, "demDt") != ed_demDt.getValue()) {
		return true;
	}
	// 취소구분
	if (ds_odrInfoForCheck.getCellData(0, "odrClsCd") != lc_odrClsCd.getValue()) {
		return true;
	}
	// 배차담당
	if (ds_odrInfoForCheck.getCellData(0, "alloccarPicId") != ed_alloccarPicId.getValue()) {
		return true;
	}
	// 특이사항
	if (ds_odrInfoForCheck.getCellData(0, "rmk") != txt_rmk.getValue()) {
		return true;
	}
	// 화물위탁증정보
	if (ds_odrInfoForCheck.getCellData(0, "trnsRealMchtClntNm") != ed_trnsRealMchtClntNm.getValue()) {
		return true;
	}
	// 화물위탁증정보
	if (ds_odrInfoForCheck.getCellData(0, "trnsRealMchtClntTelNo") != ed_trnsRealMchtClntTelNo.getValue()) {
		return true;
	}
	// 화물위탁증정보
	if (ds_odrInfoForCheck.getCellData(0, "trnsCnsgMchtClntNm") != ed_trnsCnsgMchtClntNm.getValue()) {
		return true;
	}
	// 화물위탁증정보
	if (ds_odrInfoForCheck.getCellData(0, "trnsCnsgMchtClntTelNo") != ed_trnsCnsgMchtClntTelNo.getValue()) {
		return true;
	}
	return false;
};

// 임시 저장
scwin.f_temp_save = async function() {
    let chkVal = "";
    ed_lduldWrkPlCd.setMandatory(true); 
    ed_lduldZip.setMandatory(true); 

	if (scwin.statusFlag == "C") { // 신규
		if (ds_odrInfo.getModifiedIndex()) {
			if (lc_ctrtNo.getvalue("ctrtNo") == "선택" ) {
				await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["계약번호"]); // @은(는) 필수 입력 항목입니다
				return false;
			}

			// 요청거래처가 내부거래매핑 거래처이면 진행안됨.
            chkVal = await scwin.f_checkInternal();
			if (chkVal) {
				await $c.gus.cfAlertMsg("요청처는 원 청구거래처를 입력해주세요.");
				ed_reqClntNo.focus();
				return false;
			}

            chkVal = await $c.gus.cfValidate([tbl_odrInfoArea, tbl_odrInfoArea2], null, true);
            if (chkVal) {
                let valChk = await scwin.f_validate();
				if (!valChk)
                    return;

                chkVal = await $c.gus.cfValidate([gr_cntrInfo], null, true); 
                if (chkVal) {
                    if (await $c.win.confirm(MSG_CM_CRM_001)) { // 저장하시겠습니까?
                        // 오더확정구분을 9으로 변경
                        ds_odrInfo.setCellData(0, "odrDcsnYn", 0);

                        // 하차지를 상차지로 대입
                        ds_odrInfo.setCellData(0, "lduldWrkPlCd", ds_odrInfo.getCellData(0, "dptWrkPlCd"));
                        ds_odrInfo.setCellData(0, "lduldZip", ds_odrInfo.getCellData(0, "dptZip"));

                        scwin.f_setValueBeforeSave(); // 저장하기전 데이터 세팅
                        scwin.f_registByOdrKndCd();   // 오더종류별 저장
                    }
                }
            }
		} else {
            if ($c.data.isModified(ds_cntrInfo)) {
				if ($c.gus.cfValidate(tbl_odrInfoArea, null, true))
                    return;
			} else {
				await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["컨테이너오더"]); // @은(는) 변경된 사항이 없습니다.
			}
		}
	}
};

