						if (ds_cntrInfo.getModifiedIndex()) {
							await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["컨테이너 정보가 변경되었습니다.\n\n수정사유"]); // @은(는) 필수 입력 항목입니다
