							await $c.gus.cfAlertMsg("변경사항이 없습니다.");
							return false;
						}
					} else {
						// 사유내용이 입력된경우
						if (ed_rsnTxt.getValue() != "") {
							// 통과
						} else {
							// 컨테이너 변경여부 확인
							if (ds_cntrInfo.getModifiedIndex()) {
								await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["컨테이너 정보가 변경되었습니다.\n\n수정사유"]); // @은(는) 필수 입력 항목입니다
								ed_rsnTxt.focus();
								return false;
							} else {
								await $c.gus.cfAlertMsg("변경사항이 없습니다.");
								return false;
							}
						}
					}
				}
			}

			if (lc_ctrtNo.getValue() == "선택") {
				await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["계약번호"]); // @은(는) 필수 입력 항목입니다
				return false;
			}

			// 요청거래처가 내부거래매핑 거래처이면 진행안됨.
			if (await scwin.f_checkInternal()) {
				await $c.gus.cfAlertMsg("요청처는 원 청구거래처를 입력해주세요.");
