            chkVal = await $c.gus.cfValidate([tbl_odrInfoArea, tbl_odrInfoArea2], null, true);
			if (chkVal) {
                let valChk = await scwin.f_validate();
				if (!valChk)
                    return;

                chkVal = await $c.gus.cfValidate([gr_cntrInfo], null, true); 
                if (chkVal) {
                    if (await $c.win.confirm(MSG_CM_CRM_001)) { // 저장하시겠습니까?
                        // 오더확정구분을 0으로 변경
                        ds_odrInfo.setCellData(0, "odrDcsnYn", 0);
                        scwin.f_setValueBeforeSave(); // 저장하기전 데이터 세팅
                        scwin.f_registByOdrKndCd(); // 오더종류별 저장
                    }
                }
			}
		} else {
			if (ds_cntrInfo.getModifiedIndex()) {
				if ($c.gus.cfValidate(tbl_odrInfoArea, null, true))
                    return;
			} else {
				await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["컨테이너오더"]); // @은(는) 변경된 사항이 없습니다.
			}
		}
	}
};

// 내부매핑거래처인지 체크
scwin.f_checkInternal = async function() {
	var reqClntNo = ed_reqClntNo.getValue();
	var internalCnt = 0;
	for (var i = 0; i < ds_internalTxn.getRowCount(); i++) {
		if (ds_internalTxn.getCellData(i, "cd") == reqClntNo) {
			internalCnt++;
		}
	}
	if (internalCnt > 0) {
		return true;
	}
	return false;
};

// 유효성체크
scwin.f_validate = async function() {
	// 오더기본정보-상,하차 일,시간체크
	if (!scwin.f_chkDate(ed_wrkStDt.getValue(), ed_wrkEndDt.getValue())) {
		await $c.gus.cfAlertMsg(MSG_CM_ERR_061, ["상차일자", "작업일자 이전"]); // "@은(는) @이어야 합니다."
		ed_wrkStDt.focus();
		return false;
	}
	if (!scwin.f_chkDate(ed_wrkEndDt.getValue(), ed_lduldDt.getValue())) {
		await $c.gus.cfAlertMsg(MSG_CM_ERR_061, ["작업일자", "하차일자 이전"]); // "@은(는) @이어야 합니다."
		ed_wrkEndDt.focus();
		return false;
	}
	if (!scwin.f_chkTime(ed_wrkStDt.getValue(), ed_wrkStHh.getValue(), ed_wrkEndDt.getValue(), ed_wrkEndHh.getValue())) {
		await $c.gus.cfAlertMsg(MSG_CM_ERR_061, ["상차시간", "작업시간 이전"]); // "@은(는) @이어야 합니다."
		ed_wrkStDt.focus();
		return false;
	}
	if (!scwin.f_chkTime(ed_wrkEndDt.getValue(), ed_wrkEndHh.getValue(), ed_lduldDt.getValue(), ed_lduldHh.getValue())) {
		await $c.gus.cfAlertMsg(MSG_CM_ERR_061, ["작업시간", "하차시간 이전"]); // "@은(는) @이어야 합니다."
		ed_wrkEndDt.focus();
		return false;
	}

	// 철송구간 체크
	if (scwin.f_railCheck() == true && ed_railroadDptWrkPlCd.getValue() == "" && ed_railroadArvWrkPlCd.getValue() == "") {
		await $c.gus.cfAlertMsg("철송구간이 있습니다. \n철송구간을 입력하세요.");
		ed_railroadDptWrkPlCd.focus();
		return false;
	}
	if (ed_railroadDptWrkPlCd.getValue() != "" ) {
		if (ed_railroadArvWrkPlCd.getValue() == "") {
			await $c.gus.cfAlertMsg("철송구간은 From ~ To 둘다 있어야 합니다.\n 철송구간 To를 입력하세요.");
			ed_railroadArvWrkPlCd.focus();
			return false;
		}
	}
	if (ed_railroadArvWrkPlCd.getValue() != "" ) {
		if (ed_railroadDptWrkPlCd.getValue == "") {
			await $c.gus.cfAlertMsg("철송구간은 From ~ To 둘다 있어야 합니다.\n 철송구간 From을 입력하세요.");
			ed_railroadDptWrkPlCd.focus();
			return false;
		}
	}

	// 컨테이너목록이 한건도 입력되지 않은 경우
	if (ds_cntrInfo.getRowCount() == 0) {
		await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["컨테이너목록"]); // @은(는) 필수 입력 항목입니다
		return false;
	}
	if (scwin.f_setWrkPath() == false) {// 작업경로 입력확인
		await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["작업경로"]); // @은(는) 필수 입력 항목입니다
		return false;
	}
	if (scwin.f_chkCntrNo() == false) {// 컨테이너번호 입력확인
		await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["컨테이너번호"]); // @은(는) 필수 입력 항목입니다
		return false;
	}
	return true;
};

// 문자체크
scwin.containsCharsOnly = function(objValue, chars) {
	for (var inx = 0; inx < objValue.length; inx++) {
		if (chars.indexOf(objValue.charAt(inx)) != -1) 
            return false;
	}
	return true;
};

// 컨테이너 철송확인 
scwin.f_railCheck = function() {
	var chars = "R";	
	var cntrRows = ds_cntrInfo.getRowCount();
	var wrkPathRows = ds_ctrtWrkPath.getRowCount();
	var chekRail = "";
	for (var i = 0; i < wrkPathRows; i++) {
		if (scwin.containsCharsOnly(ds_ctrtWrkPath.getCellData(i,  "rmk"), chars) == false) {
			for (var j = 0; j < cntrRows; j++) {
				if (ds_ctrtWrkPath.getCellData(i, "ctrtWrkPathSeq") == ds_cntrInfo.getCellData(j, "ctrtWrkPathSeq")) {
					return true;
					break;
				}
			}
		}
	}
	return false;
};

// 컨테이너 번호 입력 확인
scwin.f_chkCntrNo = function() {
	var cntrRows = ds_cntrInfo.getRowCount();
	for (var i = 0; i < cntrRows; i++) {
		if (ds_cntrInfo.getCellData(i, "cntrNo") == "") {
			return false;
		}
	}
};

// 컨테이너 작업경로 입력 확인
scwin.f_setWrkPath = function() {
	var cntrRows = ds_cntrInfo.getRowCount();
	var pathSeq = "";

	for (var i = 0; i < cntrRows; i++) {
		if (ds_cntrInfo.getCellData(i, "ctrtWrkPathSeq") != "0" && ds_cntrInfo.getCellData(i, "ctrtWrkPathSeq") != "") {
			pathSeq = ds_cntrInfo.getCellData(i, "ctrtWrkPathSeq");
			break;
		}
	}
	if (pathSeq == "0" || pathSeq == "") {
		return false;
	} else {
		for (var i = 0; i < cntrRows; i++) {
			if (ds_cntrInfo.getCellData(i,  "ctrtWrkPathSeq") == "0" || ds_cntrInfo.getCellData(i, "ctrtWrkPathSeq") == "") {
				if (ds_cntrInfo.getCellData(i - 1, "ctrtWrkPathSeq") == "0" || ds_cntrInfo.getCellData(i - 1, "ctrtWrkPathSeq") == "") {
					ds_cntrInfo.setCellData(i, "ctrtWrkPathSeq", pathSeq);
				} else {
					ds_cntrInfo.setCellData(i, "ctrtWrkPathSeq", ds_cntrInfo.getCellData(i - 1, "ctrtWrkPathSeq"));
				}
			}
		}
	}
};

// 시작일자, 종료일자 유효성 체크
scwin.f_chkDate = function(strDate, endDate) {
	var differDays = $c.date.diffDate(strDate, endDate);
	if (differDays >= 0) {
        return true;
    } else {
        return false;
    }
};

// 시작시간, 종료시간 유효성 체크
scwin.f_chkTime = function(strDate, strTime, endDate, endTime) {
	var differTime = eval(endDate + endTime) - eval(strDate + strTime);
	if (differTime > 0) {
        return true;
    } else {
        return false;
    }
};

// 오더별로 저장하기전에 데이터셋value들 재세팅
