    ds_odrInfo.setCellData(0, "realMchtClntNo", ds_odrInfo.getCellData(0, "ctrtClntNo")); // 실화주거래처번호 계약거래처로 셋팅
	ds_odrInfo.setCellData(0, "regBranCd", scwin.lobranCd); // 등록점소 - 사용자 설정 물류점소

    // 저장시 CH코드 0으로 초기화
	switch (scwin.odrKndCd) {
        // 수입일반컨테이너오더
        case DsConstants.ODR_KND_CD_IMP_GNRL_CNTR_ODR :	
            ds_odrInfo.setCellData(0, "chClsCd", "0"); // CH구분코드
		break;
		default:																  
            ds_odrInfo.setCellData(0, "chClsCd", ""); // CH구분코드
        break;
	}

    // <% if (linkPage.equals("webOdr")) { 		%>
    //     ds_odrInfo.NameValue(1, "clntMgntNo") = "<%=reqNo %>"; //웹오더 의뢰번호
    // <%	} %>
};

// 오더종류별 신규저장
scwin.f_registByOdrKndCd = async function() {
    // 저장시 컨테이너목록 RowStatus 변경("CREATE")
    for (var i = 0; i < ds_cntrInfo.getRowCount(); i++){
        ds_cntrInfo.modifyRowStatus(i, "C");
    };

    ds_cndOdrNo.removeAll();
	sbm_registByOdrKndCd.userData1 = "noError";
    let e = await $c.sbm.execute(sbm_registByOdrKndCd);
	await scwin.sbm_registByOdrKndCd_submitdone(e);
};

// 오더 수정 저장
