		|| ds_odrInfo.getOriginalCellData(0, "wrkEndDt") != ds_odrInfo.getCellData(0, "wrkEndDt")
		|| ds_odrInfo.getOriginalCellData(0, "lduldDt") != ds_odrInfo.getCellData(0, "lduldDt")
		|| ds_odrInfo.getOriginalCellData(0, "wrkStHh") != ds_odrInfo.getCellData(0, "wrkStHh")
		|| ds_odrInfo.getOriginalCellData(0, "wrkEndHh") != ds_odrInfo.getCellData(0, "wrkEndHh")
		|| ds_odrInfo.getOriginalCellData(0, "lduldHh") != ds_odrInfo.getCellData(0, "lduldHh")) {

            // 가우스   :  0: Normal, 1: Insert, 2: Delete, 3: Update, 4: Logical
            // 웹스퀘어 :  R:초기상태, C:삽입, D:삭제, U:갱신, V:삽입 후 삭제
			for (var i = 0; i < cntrRows; i++) {
				if (ds_cntrInfo.getRowStatus(i) == "R") {
					ds_cntrInfo.setCellData(i, "arvWrkPlNm", "update");
                    ds_cntrInfo.modifyRowStatus(i, "U");
				}
			}
	}



	sbm_updateByOdrKndCd.userData1 = "noError";
    let e = await $c.sbm.execute(sbm_updateByOdrKndCd);
    await scwin.sbm_updateByOdrKndCd_submitdone(e);
};

