// 삭제
scwin.f_delete = async function() {
    let msg  = $c.data.getMessage(MSG_CM_CRM_008, ds_odrInfo.getCellData(0, "odrNo").trim());
    let conf = await $c.win.confirm("오더번호 : "+ msg);
  	if (conf) {
        if (ds_deleteOrderCond.getRowCount() > 0) {
 			ds_deleteOrderCond.removeAll();
 		}

 		let rowIndex = ds_deleteOrderCond.insertRow();
 		ds_deleteOrderCond.setCellData(rowIndex, "odrNo", ds_odrInfo.getCellData(0, "odrNo").trim());
 		ds_deleteOrderCond.setCellData(rowIndex, "odrKndCd", scwin.odrKndCd);
 		ds_deleteOrderCond.setCellData(rowIndex, "impExpDomesticClsCd", scwin.impExpClsCd);
 		ds_deleteOrderCond.setCellData(rowIndex, "selfClsCd", ds_odrInfo.getCellData(0, "selfClsCd").trim());

		sbm_deleteOrderCond.userData1 = "noError";
        let e = await $c.sbm.execute(sbm_deleteOrderCond);
        await scwin.sbm_deleteOrderCond_submitdone(e);
    }
};

// 확정
scwin.f_confirmOrder = async function() {
	// 작업경로가 지정된 경우만 오더확정 가능
