// 행추가
scwin.f_addRow = function () {
	let index = ds_cntrInfo.insertRow();
    ds_cntrInfo.setCellData(index, 'cntrSeq', 0);
    gr_cntrInfo.setFocusedCell(index, 0);
};

// 행삭제
scwin.f_deleteRow = async function () {
	var cntrInfoRows = ds_cntrInfo.getRowCount();
	var arrRowNo = new Array();
	var idx		  = 0;
	var alertStr  = "";

	if (cntrInfoRows > 0) {
		for (var i = 0; i < cntrInfoRows; i++) {
            if (ds_cntrInfo.getRowPosition() == i) {
				// 실적체크
				if (!$c.gus.cfIsNull(ds_cntrInfo.getCellData(ds_cntrInfo.getRowPosition(), "wrkRsltsNo"))) {
                    await $c.gus.cfAlertMsg("실적이 발생한 컨테이너는 삭제할 수 없습니다."); // (확인할 것)
					return;
				} else {
                    let rowStatus = ds_cntrInfo.getRowStatus(i);
                    if(rowStatus == "C") {
					    ds_cntrInfo.removeRow(i);
                    } else {
                        ds_cntrInfo.deleteRow(i);
                    }
				}
			}
		}
        cntrTotalRows.setValue(ds_cntrInfo.getTotalRow());
	}
};

// 행취소
scwin.f_undoRow = function () {
    let rowIndex = ds_cntrInfo.getRowPosition();
    if(ds_cntrInfo.getRowStatus(rowIndex) == "C") {
	    ds_cntrInfo.removeRow(rowIndex);
    } else {
        ds_cntrInfo.undoRow(rowIndex);
    }
};

scwin.f_retrieveCntrBasisInfo = async function (cntrNo) {
	if ($c.gus.cfIsNull(ed_lineCd.getValue().trim())) {
		await $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["라인코드"]); // @을(를) 입력하십시오
		return;
	}
    // 검색데이터셋 값세팅
	if (ds_cndBlNo.getRowCount() > 0) 
        ds_cndBlNo.removeAll();

	let index = ds_cndBlNo.insertRow();
	ds_cndBlNo.setCellData(index, "cvsslMgntNo", ed_cvsslMgntNo.getValue().trim());
	ds_cndBlNo.setCellData(index, "impExpClsCd", "I");
	ds_cndBlNo.setCellData(index, "hblNo", ed_blNo.getValue().trim());
	ds_cndBlNo.setCellData(index, "odrKndCd", scwin.odrKndCd);
	ds_cndBlNo.setCellData(index, "cntrNo", cntrNo);
	ds_cndBlNo.setCellData(index, "selfClsCd", lc_selfClsCd.getValue());

	sbm_retrieveCntrBasisInfo.userData1 = "noError";
    let e = await $c.sbm.execute(sbm_retrieveCntrBasisInfo);
	await scwin.sbm_retrieveCntrBasisInfo_submitdone(e);
};

// 매출부서, 청구부서 세팅
scwin.f_setSellAndBilgDept = async function () {
    var deptCd1 = scwin.lobranCd; // 등록점소 - 사용자 설정 물류점소
    var orgdeptCd1 = deptCd1;
    var deptCd = ""; // 부서코드

    if (deptCd1.length > 2) {
        deptCd1 = deptCd1.substr(0, 2);
    } else {
        return;
    }

    deptCd = deptCd1 + "2";

    // 매출부서 세팅
    var newDeptCd = scwin.rentcarOfcCd;
    if ($c.gus.cfIsNull(newDeptCd)) {
        ed_sellLodeptCd.setValue(deptCd);
    } else {
        ed_sellLodeptCd.setValue(newDeptCd);
    }

    if (deptCd == "3A2") {
        ed_sellLodeptCd.setValue("3A21");
    }

    await scwin.f_openCommonPopUp(2, 'SELL', 'T', 'F', 'F', 'F');

    // 청구부서 세팅 - 부산은 6A3셋팅함. - 보랄 변경건 추가
    if ($c.gus.cfIsNull(newDeptCd)) {
        if (orgdeptCd1 == "6AA") {
            ed_bilgLodeptCd.setValue("6A1");
        } else if (deptCd == "3A2") {
            ed_bilgLodeptCd.setValue("3A21");
        } else {
            ed_bilgLodeptCd.setValue(deptCd);
        }
    } else {
        ed_bilgLodeptCd.setValue(newDeptCd);
    }

    await scwin.f_openCommonPopUp(2, 'BILG', 'T', 'F', 'F', 'F');
};

