scwin.sbm_retrieve_submitdone = async function (e) {
	if (e.responseJSON.resultDataSet[0].Code < 0)  {
        await $c.win.alert(e.responseJSON.resultDataSet[1].Msg);
        return; 
    }

    var v_odrNo = ds_odrInfo.getCellData(0, "odrNo");
    var v_odrKndCd = ds_odrInfo.getCellData(0, "odrKndCd");
    var odrDcsnYn = ds_odrInfo.getCellData(0, "odrDcsnYn"); // 확정여부

    var paramObj = {
        odrNo : v_odrNo,
        linkPage : "odrList"
    }
    let options = {
        "openAction": "exist"
    }
	var MSG_CM_CRM = "Page로 이동하시겠습니까?";

    if (ds_odrInfo.getRowCount() > 0) {
        ds_odrInfo.setRowPosition(0);
	}

	// 수정사유 TR숨기기 hurrah by 20140219
    if (odrDcsnYn == DsConstants.YN_YES) { // 오더가 확정된 경우
	    tr_editTitle.hide();
    }

    lc_rsnCd.setSelectedIndex(0);

	if (v_odrKndCd == "C2" || v_odrKndCd == "CX") { // 수입일반오더
		await scwin.f_set("RETRIEVE");
        await scwin.f_retrieveCtrtNo();
        await scwin.f_openCommonPopUp(1, 'BILG', 'T', 'F', 'F', 'F');
		await scwin.f_openCommonPopUp(1, 'REQ', 'T', 'F', 'F', 'F');
		ds_odrInfo.setCellData(0, "ctrtNo", ds_odrInfo.getOriginalCellData(0, "ctrtNo"));
        cntrTotalRows.setValue(ds_cntrInfo.getTotalRow());
	} else {
        let ret= await $c.gus.cfAlertMsg("해당 오더의 정보가 없습니다.");
        if (ret) {
            await scwin.f_set("INIT", "CREATE");
            if (v_odrKndCd == "C1" || v_odrKndCd == "CS" || v_odrKndCd == "CT") { // 수입본선오더
                //strOrderDetailUrl = "/tn/sd/odrmgnt/cntrodrreg/tn_201_02_05b.jsp";
                if (await $c.win.confirm("수입본선오더" + MSG_CM_CRM)) {
                // 	<% if (linkPage.equals("webOdr")) { out.print("parent."); } %>
                // 	cfTabMenuUpdate( strOrderDetailUrl+condition , "수입본선오더") ;
                    $c.win.openMenu("수입본선 오더(C1/CS/CT)", "/ui/tn/sd/odrmgnt/cntrodrreg/tn_201_02_05b.xml", "tn_201_02_05b.jsp", paramObj, options);
                }
            } else if (v_odrKndCd == "C3" || v_odrKndCd == "CW" || v_odrKndCd == "CR" || v_odrKndCd == "CP") { // 수출본선오더
                // strOrderDetailUrl = "/tn/sd/odrmgnt/cntrodrreg/tn_201_02_06b.jsp";
                // if (cfConfirmMsg("수출본선오더" + MSG_CM_CRM)) {
                // 	<% if (linkPage.equals("webOdr")) { out.print("parent."); } %>
                // 	cfTabMenuUpdate( strOrderDetailUrl+condition , "수출본선오더") ;
                // }
                if (await $c.win.confirm("수출본선오더" + MSG_CM_CRM)) {
                    $c.win.openMenu("수출본선 오더(C3/CW/CR/CP)", "/ui/tn/sd/odrmgnt/cntrodrreg/tn_201_02_06b.xml", "tn_201_02_06b.jsp", paramObj, options);
                }
            } else if (v_odrKndCd == "C4") { // 수출일반오더
                // strOrderDetailUrl = "/tn/sd/odrmgnt/cntrodrreg/tn_201_02_04b.jsp";
                // if (cfConfirmMsg("수출일반오더" + MSG_CM_CRM)) {
                // 	<% if (linkPage.equals("webOdr")) { out.print("parent."); } %>
                // 	cfTabMenuUpdate( strOrderDetailUrl+condition , "수출일반오더") ;
                // }
                if (await $c.win.confirm("수출일반오더" + MSG_CM_CRM)) {
                    $c.win.openMenu("수출일반 오더(C4)", "/ui/tn/sd/odrmgnt/cntrodrreg/tn_201_02_04b.xml", "tn_201_02_04b.jsp", paramObj, options);
                }
            } else if (v_odrKndCd == "C5" || v_odrKndCd == "C6" || v_odrKndCd == "C7") { // 기타오더
                // strOrderDetailUrl = "/tn/sd/odrmgnt/cntrodrreg/tn_201_02_07b.jsp";
                // if (cfConfirmMsg("기타오더" + MSG_CM_CRM)) {
                // 	<% if (linkPage.equals("webOdr")) { out.print("parent."); } %>
                // 	cfTabMenuUpdate( strOrderDetailUrl+condition , "기타오더") ;
                // }
                if (await $c.win.confirm("기타오더" + MSG_CM_CRM)) {
                    $c.win.openMenu("기타 오더(C5/C6/C7)", "/ui/tn/sd/odrmgnt/cntrodrreg/tn_201_02_07b.xml", "tn_201_02_07b.jsp", paramObj, options);
                }
            }
        }
	}

    // 특이사항 숨김여부체크
    if (!$c.gus.cfIsNull(lc_ctrtNo.getValue())) {
        btn_saveRmk.hide();
	} else {
        btn_saveRmk.show();
	}
};

scwin.sbm_retrieveCtrtNo_submitdone = async function (e) {
	if (e.responseJSON.resultDataSet[0].Code < 0)  {
        await $c.win.alert(e.responseJSON.resultDataSet[1].Msg);
        return; 
    }

	let ctrtNoRows = ds_ctrtNo.getRowCount();
    if (ds_ctrtNo.getTotalRow() == 0) {
        scwin.f_clearDataByCtrtNo();
        if (ed_ctrtClntNo.getValue().trim() != "" && ed_ctrtClntNm.getValue().trim() != "") {
            await $c.gus.cfAlertMsg("거래처 " + ed_ctrtClntNm.getValue() + "의 " + MSG_CM_ERR_049, ["계약번호"]);
            return false;
        }
    } else {
        for (var i = 0; i < ds_ctrtNo.getTotalRow(); i++) {
            ds_ctrtNo.setCellData(i, "label", ds_ctrtNo.getCellData(i, "ctrtNo") + " (" + ds_ctrtNo.getCellData(i, "clntPicNm") + ":~" + ds_ctrtNo.getCellData(i, "ctrtEndDt") + ":" + ds_ctrtNo.getCellData(i, "crcCd") + ")");
        }

        ds_ctrtNo.sort("ctrtNo", 1);
        lc_ctrtNo.setSelectedIndex(-1);
        lc_ctrtNo.setValue(ds_ctrtNo.getCellData(0, "ctrtNo"));
    }
};

scwin.sbm_retrieveCtrtNo2_submitdone = async function (e) {
	if (e.responseJSON.resultDataSet[0].Code < 0)  {
        await $c.win.alert(e.responseJSON.resultDataSet[1].Msg);
        return; 
    }

	let ctrtNoRows = ds_ctrtNo2.getRowCount();
	if (ctrtNoRows > 0) {
		// 계약번호가 서로 다른 것이 있는 경우, 선택을 default로 보여주기 위한 process
		var sameYn = "N";
        for (var i = 0; i < ctrtNoRows; i++) {
            var ctrtNo = ds_ctrtNo2.getCellData(i, "ctrtNo").substring(0, 8);
            for (var j = 0; j < ds_ctrtNo2.getRowCount(); j++) {
                if (1 == ds_ctrtNo2.getCellData(j, "mgntTrgtClntYn")) {
                    sameYn = "Y";
                    break;
                }
            }
        }

		if (sameYn == "Y") {
            await $c.gus.cfAlertMsg("청구처가 관리대상 거래처 입니다.");
            ds_bilgClntNo.removeAll();
			ed_bilgClntNo.setValue("");
			ed_bilgClntNo.focus();
		}
	} else {
        await $c.gus.cfAlertMsg("청구처가 관리대상 거래처 입니다.");
	}

    if (!$c.gus.cfIsNull(ed_bilgClntNo.getValue())) {
		scwin.f_openBilgClnt();
	}

	// 특이사항 숨김여부체크
    if (!$c.gus.cfIsNull(lc_ctrtNo.getValue())) {
        btn_saveRmk.hide();
	} else {
        btn_saveRmk.show();
	}
};

scwin.sbm_retrieveCntrBasisInfo_submitdone = async function (e) {
	if (e.responseJSON.resultDataSet[0].Code < 0)  {
        await $c.win.alert(e.responseJSON.resultDataSet[1].Msg);
        return; 
    }

	if (ds_addCntrInfo.getRowCount() > 0) {
		if (ds_addCntrInfo.getCellData(0, "blNo") != ed_blNo.getValue().trim()) {
			await $c.gus.cfAlertMsg("해당컨테이너의 B/L NO가 오더정보의 B/L NO와 상이합니다.\n컨테이너를 다시 입력하여 주십시오.");
			ds_cntrInfo.setCellData(ds_cntrInfo.getRowPosition(), "cntrNo", "");
			return;
		} else {
			ds_cntrInfo.setCellData(ds_cntrInfo.getRowPosition, "arrvlportDtm", ds_addCntrInfo.getCellData(0, "arrvlportDtm"));
			ds_cntrInfo.setCellData(ds_cntrInfo.getRowPosition, "cntrNo", ds_addCntrInfo.getCellData(0, "cntrNo"));
			ds_cntrInfo.setCellData(ds_cntrInfo.getRowPosition, "cntrSizCd", ds_addCntrInfo.getCellData(0, "cntrSizCd"));
			ds_cntrInfo.setCellData(ds_cntrInfo.getRowPosition, "cntrTypCd", ds_addCntrInfo.getCellData(0, "cntrTypCd"));
			ds_cntrInfo.setCellData(ds_cntrInfo.getRowPosition, "fullEmptyClsCd", ds_addCntrInfo.getCellData(0, "fullEmptyClsCd"));
			ds_cntrInfo.setCellData(ds_cntrInfo.getRowPosition, "wt",  ds_addCntrInfo.getCellData(0, "wt"));
			ds_cntrInfo.setCellData(ds_cntrInfo.getRowPosition, "impSealNo",  ds_addCntrInfo.getCellData(0, "impSealNo"));
			ds_cntrInfo.setCellData(ds_cntrInfo.getRowPosition, "blNo", ds_addCntrInfo.getCellData(0, "blNo"));
			ds_cntrInfo.setCellData(ds_cntrInfo.getRowPosition, "arvWrkPlCd", ds_addCntrInfo.getCellData(0, "arvWrkPlCd"));
			ds_cntrInfo.setCellData(ds_cntrInfo.getRowPosition, "arvWrkPlNm", ds_addCntrInfo.getCellData(0, "arvWrkPlNm"));
			ds_cntrInfo.setCellData(ds_cntrInfo.getRowPosition, "odrNo", ds_odrInfo.getCellData(0, "odrNo"));
            cntrTotalRows.setValue(ds_cntrInfo.getTotalRow());

			if (ds_addCntrInfo.getRowCount() > 0) 
                ds_addCntrInfo.removeAll();
		}
	} else {
		await $c.win.alert("해당컨테이너 정보가 없습니다.");
	}
};

