//-------------------------------------------------------------------------
// 공통팝업호출 callBack
//-------------------------------------------------------------------------
// 계약거래처
scwin.callBackClntCtrt = function(rtnList) {
    $c.gus.cfSetReturnValue(rtnList, ed_ctrtClntNo, ed_ctrtClntNm);

    // 화물위탁증 세팅을 위한 값 초기화
    ed_trnsRealMchtClntNm.setValue("");
    ed_trnsRealMchtClntTelNo.setValue("");
    ed_trnsCnsgMchtClntNm.setValue("");
    ed_trnsCnsgMchtClntTelNo.setValue("");

    // 실화주세팅
    if (rtnList != null && rtnList[0] != "N/A") {
        var strToken = rtnList[9].split("?");
        // 운송사(03)가 아니면
        if (rtnList[2] != "03") {
            // 공통거래처체크, 공통거래처가 아니면 실화주에 계약거래처 세팅
            if (ed_ctrtClntNo.getValue().substr(0,4) != "9999") {
                ed_trnsRealMchtClntNm.setValue(rtnList[1]);
                ed_trnsRealMchtClntTelNo.setValue(strToken[1]);
            }

        } else {
            // 운송사인 경우 전역변수에 저장
            scwin.gClntClsCd = rtnList[2];
        }					
    }

    scwin.f_retrieveCtrtNo(); //계약번호 가져오기
};

// 청구거래처
scwin.callBackOpenBilgClnt = function(rtnList) {
    if (rtnList == null || rtnList[0] == "N/A") {
        return;
    }

	let strToken = rtnList[9].split("?");
	if (scwin.gClntClsCd == "03") {
		// 주선업자 세팅
		if (rtnList != null && rtnList[0] != "N/A") {
			// 공통거래처체크, 공통거래처가 아니면 주선업자에 계약거래처 세팅
			if (ed_ctrtClntNo.getValue().substr(0, 4) != "9999") {
				ed_trnsCnsgMchtClntNm.setValue(rtnList[1]);
				ed_trnsCnsgMchtClntTelNo.setValue(strToken[1]);
			}
		}
	} else {
		if (scwin.statusFlag=="R") {

		} else {
			// 청구거래처의 매출구분이 운송사가 아니면 실화주, 운송사면 주선업자에 세팅. 김병찬대리 요청
			if (rtnList[2]!="03") {
				if (ed_bilgClntNo.getValue().substr(0, 4) == "9999") {
					ed_trnsRealMchtClntNm.setValue("");
					ed_trnsRealMchtClntTelNo.setValue("");
				} else {
					ed_trnsRealMchtClntNm.setValue(rtnList[1]);
					ed_trnsRealMchtClntTelNo.setValue(strToken[1]);
				}
			} else {
				if (ed_bilgClntNo.getValue().substr(0, 4) == "9999") {
					ed_trnsCnsgMchtClntNm.setValue("");
					ed_trnsCnsgMchtClntTelNo.setValue("");
				} else {
					ed_trnsCnsgMchtClntNm.setValue(rtnList[1]);
					ed_trnsCnsgMchtClntTelNo.setValue(strToken[1]);
				}
			}
		}
	}
};

// 청구거래처
scwin.callBackClntBilg = function(rtnList) {
    if (rtnList != null) {
        if (rtnList[0] != "N/A") {
            ed_bilgClntNo.setValue(rtnList[0]);

            // 20170324 청구처 남동발전 일경우 DONO, 반납일 입력창 보여주고 아닐경우 안보여줌
            scwin.f_getCtrtClntNamDongYn(ed_bilgClntNo.getValue(), "f_openCommonPopUp");							

            // 사용자편의를 위하여 데이터셋에 추가
            var sameYn = "N";
            for (var i =0 ; i < ds_bilgClntNo.getRowCount(); i++) {
                if (ed_bilgClntNo.getValue().trim() == ds_bilgClntNo.getCellData(i, "clntNo")) {
                    sameYn = "Y";
                    lc_bilgClntNm.setSelectedIndex(i);
                    return;
                }
            }

            if (sameYn == "N") {
                let rowIndex = ds_bilgClntNo.insertRow();
                ds_bilgClntNo.setCellData(rowIndex, "clntNo", rtnList[0]);
                ds_bilgClntNo.setCellData(rowIndex, "clntNm", rtnList[1]);
                lc_bilgClntNm.setSelectedIndex(ds_bilgClntNo.getRowCount()-1);
            }

            scwin.f_retrieveCtrtNo2(); // 계약번호 가져오기

            // 화물위탁증 세팅을 위한 값 초기화
            if ($c.gus.cfIsNull(ed_odrNo.getValue())) {
                ed_trnsRealMchtClntNm.setValue("");
                ed_trnsRealMchtClntTelNo.setValue("");
                ed_trnsCnsgMchtClntNm.setValue("");
                ed_trnsCnsgMchtClntTelNo.setValue("");
            }

            // 계약거래처가 운송사인 경우
            var strToken = rtnList[9].split("?");
            if (scwin.gClntClsCd == "03") {
                // 주선업자 세팅
                if (rtnList != null && rtnList[0] != "N/A") {
                    // 공통거래처체크, 공통거래처가 아니면 주선업자에 계약거래처 세팅
                    if (ed_ctrtClntNo.getValue().substr(0,4) != "9999") {
                        ed_trnsCnsgMchtClntNm.setValue(rtnList[1]);
                        ed_trnsCnsgMchtClntTelNo.setValue(strToken[1]);
                    }
                }
            } else {
                if (scwin.statusFlag=="R") {

                } else {
                    // 청구거래처의 매출구분이 운송사가 아니면 실화주, 운송사면 주선업자에 세팅. 김병찬대리 요청
                    if (rtnList[2] != "03") {
                        ed_trnsRealMchtClntNm.setValue(rtnList[1]);
                        ed_trnsRealMchtClntTelNo.setValue(strToken[1]);
                    } else {
                        ed_trnsCnsgMchtClntNm.setValue(rtnList[1]);
                        ed_trnsCnsgMchtClntTelNo.setValue(strToken[1]);
                    }
                }
            }
        }
    } else {
        $c.gus.cfInitObjects([ed_bilgClntNo]);
        $c.gus.cfInitHidVal([ed_bilgClntNo]);
        lc_bilgClntNm.setSelectedIndex(-1);
    }
};

// 요청거래처
scwin.callBackClntReq = function(rtnList) {
    if (rtnList != null) {
        if (rtnList[0] != "N/A") {
            ed_reqClntNo.setValue(rtnList[0]);

            // 사용자편의를 위하여 데이터셋에 추가
            var sameYn = "N";
            for(var i = 0; i < ds_reqClntNo.getRowCount(); i++) {
                if(ed_reqClntNo.getValue().trim() == ds_reqClntNo.getCellData(i, "clntNo")) {
                    sameYn = "Y";
                    lc_reqClntNm.setSelectedIndex(i);
                    return;
                }
            }   

            if (sameYn == "N") {
                let rowIndex = ds_reqClntNo.insertRow();
                ds_reqClntNo.setCellData(rowIndex, "clntNo", rtnList[0]);
                ds_reqClntNo.setCellData(rowIndex, "clntNm", rtnList[1]);
                lc_reqClntNm.setSelectedIndex(ds_reqClntNo.getRowCount()-1);
            }    
        }
    } else {
        $c.gus.cfInitObjects([ed_reqClntNo]);
        $c.gus.cfInitHidVal([ed_reqClntNo]);
        lc_reqClntNm.setSelectedIndex(-1);
    }
};

