// Line
scwin.callBacklineCd = async function(rtnList) {
    if (rtnList != null) {
        if (rtnList[0] != "N/A") {
            if (scwin.odrKndCd == DsConstants.ODR_KND_CD_ON_HIRE_ODR) { // On-Hire
                if (ed_ctrtClntNo.getValue().trim() != rtnList[2]) {
                    await $c.gus.cfAlertMsg("계약거래처와 라인거래처가 상이합니다. 확인 후 다시 입력하여 주세요.");
                }
            }

            ed_lineCd.setValue(rtnList[0]);
            ed_lineNm.setValue(rtnList[1]);

            ds_odrInfo.setCellData(0, "shpCoClntNo", rtnList[4]);
            ed_shpCoClntNm.setValue(rtnList[5]);
        } else {
            $c.gus.cfInitObjects([ed_lineNm, ed_shpCoClntNm]);
            $c.gus.cfInitHidVal([ed_lineNm, ed_shpCoClntNm]);
            ds_odrInfo.setCellData(0, "shpCoClntNo", "");
        }
    } else {
        $c.gus.cfInitObjects([ed_lineCd, ed_lineNm, ed_shpCoClntNm]);
        $c.gus.cfInitHidVal([ed_lineCd, ed_lineNm, ed_shpCoClntNm]);
        ds_odrInfo.setCellData(0, "shpCoClntNo", "");
    }

    if (scwin.blInfoYn == "Y"){
	    // BL번호로 적하목록 BL 품명 정보를 조회한다.
        scwin.blInfoYn = ""; 
        scwin.f_retrieveBillOfLadingContainerList();
    }
};

