scwin.ed_wrkEndHh_onviewchange = function (info) {
    if("4AA" == scwin.lobranCd){
		let dateStr   = new Date().format("YYYYMMDD");  
	    let wrkDate = dateStr + ed_wrkEndHh.getValue(); 
	    let wrkDateDt   = wrkDate.toDate("YYYYMMDDHHmm");
		let oneHourBefore = wrkDateDt.before(0, 0, 0, 1).format("YYYYMMDDHHmm");
		let oneHourAfter = wrkDateDt.after(0, 0, 0, 1).format("YYYYMMDDHHmm");

		ed_wrkStHh.setValue(oneHourBefore.substring(8,13));
		ed_lduldHh.setValue(oneHourAfter.substring(8,13));
	}
};
